previewCss:
.darma-loader-uiverse-cyber-percent-bar {
  display: block;
  position: relative;
  height: 32px;
  width: 200px;
  background: #ffffff;
  border: 2px solid #ffffff;
  color: var(--loader-color, #df3c3c);
  overflow: hidden;
}
.darma-loader-uiverse-cyber-percent-bar::before {
  content: "";
  background: var(--loader-color, #df3c3c);
  position: absolute;
  left: 0;
  top: 0;
  width: 0;
  height: 100%;
  animation: darma-loader-uiverse-cyber-percent-bar-cyberFill 10s linear infinite;
}
.darma-loader-uiverse-cyber-percent-bar::after {
  content: "Loading";
  position: absolute;
  inset: 0;
  text-align: center;
  font-size: 18px;
  line-height: 32px;
  color: var(--loader-secondary-color, #00ffff);
  mix-blend-mode: difference;
  animation: darma-loader-uiverse-cyber-percent-bar-cyberText 10s linear infinite;
}
@keyframes darma-loader-uiverse-cyber-percent-bar-cyberFill { to { width: 100%; } }
@keyframes darma-loader-uiverse-cyber-percent-bar-cyberText {
  0% { content: "0%"; } 25% { content: "25%"; } 50% { content: "50%"; } 75% { content: "75%"; } 100% { content: "100%"; }
}

